import React, { useMemo, useState } from "react";
import { Car } from "../types/Car";
import { reserveTrack } from "../services/api";
import {
  Alert,
  Button,
  Dialog,
  DialogActions,
  DialogContent,
  DialogTitle,
  MenuItem,
  Snackbar,
  Stack,
  TextField,
  Typography,
} from "@mui/material";

const TRACKS = ["Short Circuit", "Grand Prix Circuit", "Drift Arena"] as const;

export default function ReservationDialog({
  open,
  car,
  onClose,
}: {
  open: boolean;
  car: Car | null;
  onClose: () => void;
}) {
  const [track, setTrack] = useState("");
  const [date, setDate] = useState("");
  const [name, setName] = useState("");
  const [email, setEmail] = useState("");

  const [submitting, setSubmitting] = useState(false);
  const [toast, setToast] = useState<{ type: "success" | "error"; msg: string } | null>(null);

  const canSubmit = useMemo(() => {
    if (!car) return false;
    if (!track || !date || !name || !email) return false;
    // basic email check
    if (!/^\S+@\S+\.\S+$/.test(email)) return false;
    return true;
  }, [car, track, date, name, email]);

  const handleReserve = async () => {
    if (!car || !canSubmit) return;

    setSubmitting(true);
    try {
      const result = await reserveTrack({
        carId: car.carId,
        track,
        date,
        customer: { name, email },
      });

      setToast({ type: "success", msg: `Reservation confirmed! ID: ${result.reservationId}` });
      onClose();
      // optional: reset fields after success
      setTrack("");
      setDate("");
      setName("");
      setEmail("");
    } catch {
      setToast({ type: "error", msg: "Reservation failed. Please try again." });
    } finally {
      setSubmitting(false);
    }
  };

  return (
    <>
      <Dialog open={open} onClose={onClose} maxWidth="sm" fullWidth>
        <DialogTitle>Reserve Track Experience</DialogTitle>

        <DialogContent>
          {car && (
            <Stack spacing={2} sx={{ mt: 1 }}>
              <Typography color="text.secondary">
                Car: <b>{car.make} {car.model}</b> ({car.year})
              </Typography>

              <TextField
                select
                label="Track"
                value={track}
                onChange={(e) => setTrack(e.target.value)}
                fullWidth
              >
                <MenuItem value="">Select a track</MenuItem>
                {TRACKS.map((t) => (
                  <MenuItem key={t} value={t}>
                    {t}
                  </MenuItem>
                ))}
              </TextField>

              <TextField
                label="Date"
                type="date"
                value={date}
                onChange={(e) => setDate(e.target.value)}
                fullWidth
                InputLabelProps={{ shrink: true }}
              />

              <TextField label="Name" value={name} onChange={(e) => setName(e.target.value)} fullWidth />
              <TextField
                label="Email"
                value={email}
                onChange={(e) => setEmail(e.target.value)}
                fullWidth
                helperText="We’ll send confirmation to this address."
              />
            </Stack>
          )}
        </DialogContent>

        <DialogActions sx={{ p: 2 }}>
          <Button onClick={onClose} variant="outlined" color="primary">
            Cancel
          </Button>
          <Button
            onClick={handleReserve}
            disabled={!canSubmit || submitting}
            variant="contained"
            color="primary"
          >
            {submitting ? "Reserving..." : "Confirm Reservation"}
          </Button>
        </DialogActions>
      </Dialog>

{toast && (
  <Snackbar
    open
    autoHideDuration={4500}
    onClose={() => setToast(null)}
    anchorOrigin={{ vertical: "bottom", horizontal: "center" }}
  >
    <Alert onClose={() => setToast(null)} severity={toast.type} variant="filled">
      {toast.msg}
    </Alert>
  </Snackbar>
)}
    </>
  );
}
